/**
 * @summary List stock ledger entries (move history)
 */
export const getListLedgerUrl = (params?: ListLedgerParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/ledger?${stringifiedParams}`
    : `/api/ledger`;
};

export const listLedger = async (
  params?: ListLedgerParams,
  options?: RequestInit,
): Promise<LedgerEntry[]> => {
  return customFetch<LedgerEntry[]>(getListLedgerUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListLedgerQueryKey = (params?: ListLedgerParams) => {
  return [`/api/ledger`, ...(params ? [params] : [])] as const;
};

export const getListLedgerQueryOptions = <
  TData = Awaited<ReturnType<typeof listLedger>>,
  TError = ErrorType<unknown>,
>(
  params?: ListLedgerParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listLedger>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListLedgerQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listLedger>>> = ({
    signal,
  }) => listLedger(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listLedger>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListLedgerQueryResult = NonNullable<
  Awaited<ReturnType<typeof listLedger>>
>;
export type ListLedgerQueryError = ErrorType<unknown>;

/**
 * @summary List stock ledger entries (move history)
 */

export function useListLedger<
  TData = Awaited<ReturnType<typeof listLedger>>,
  TError = ErrorType<unknown>,
>(
  params?: ListLedgerParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listLedger>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListLedgerQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
